{
  "apiVersion": "sgroups.io/v1alpha1",
  "kind": "Tenant",
  "metadata": {
    "name": "{{tenantName}}",
    "labels": {"env": "test", "team": "platform"}
  },
  "spec": {
    "displayName": "Postman Test Tenant",
    "comment": "created by postman",
    "description": "Tenant for smoke tests"
  }
}

{
  "apiVersion": "sgroups.io/v1alpha1",
  "kind": "Tenant",
  "metadata": {
    "name": "{{tenantName}}",
    "resourceVersion": "{{tenantRV}}",
    "labels": {"env": "test", "team": "platform"}
  },
  "spec": {
    "displayName": "Updated Tenant",
    "comment": "updated by postman",
    "description": "Tenant updated via PUT"
  }
}

{
  "apiVersion": "sgroups.io/v1alpha1",
  "kind": "AddressGroup",
  "metadata": {
    "name": "{{agName}}",
    "namespace": "{{namespace}}",
    "labels": {"env": "test", "team": "platform"}
  },
  "spec": {
    "displayName": "Test Address Group",
    "comment": "created by postman",
    "description": "AddressGroup for smoke tests",
    "defaultAction": "ALLOW",
    "logs": true,
    "trace": false
  }
}

{
  "apiVersion": "sgroups.io/v1alpha1",
  "kind": "AddressGroup",
  "metadata": {
    "name": "{{agName}}",
    "namespace": "{{namespace}}",
    "resourceVersion": "{{agRV}}",
    "labels": {"env": "test", "team": "platform"}
  },
  "spec": {
    "displayName": "Updated Address Group",
    "comment": "updated by postman",
    "description": "AddressGroup updated via PUT",
    "defaultAction": "DENY",
    "logs": true,
    "trace": false
  }
}
